@ARTICLE{10.1016/j.diabres.2026.113183,
	author = {Karczewska-Kupczewska M and Matulewicz N and Stefanowicz M and Dobrzycka M and Dunaj K, Kołakowski A, Myśliwiec P and Dadan J and Kowalska I},
	title = {Adipose tissue expression of Notch signaling genes in relation to insulin sensitivity and obesity in humans.},
	journal = {Diabetes Res Clin Pract},
	year = {2026},
	abstract = {AIMS: Notch signaling may regulate adipogenesis. The objective of the present study was to analyze the role of the Notch pathway in the development of insulin resistance and metabolic complications of obesity. We analyzed subcutaneous (SAT) and visceral adipose tissue (VAT) expression of Notch genes in relation to insulin sensitivity, obesity, and metabolic syndrome (MS). METHODS: Study group 1 comprised 48 individuals with normal-weight, 28 with overweight and 12 with obesity. Group 2 comprised 27 participants with overweight/obesity examined before and after weight loss. Group 3 comprised 8 individuals without obesity, 23 with obesity without MS, 29 with obesity with MS. SAT biopsy was performed in group 1 and 2. In group 3, SAT and VAT were collected during surgery. RESULTS: In group 1, SAT DLL1, NOTCH2, NOTCH4, and HEY1 were lower in individuals with obesity compared to normal-weight individuals. In group 2, weight loss increased DLL1, JAG1, NOTCH2, NOTCH4, and HES1. In group 3, both groups with obesity had lower SAT and VAT JAG1, NOTCH2, NOTCH4, and HEY1. Positive correlations between Notch genes and adipogenic genes were observed in all study groups. CONCLUSIONS: Notch signaling pathway may be associated with healthy adipose tissue through regulation of adipogenesis in humans.},
	doi = {10.1016/j.diabres.2026.113183},
	pmid = {41734827 [Indexed for MEDLINE]}
}

@ARTICLE{10.1096/fj.202504725R,
	author = {Wang Y and Edin ML and Jing N and Lih FB and Yang J and Yeliseyev V and Zeldin DC and Zhang G},
	title = {Gut Microbiota Modulate Adipose Eicosanoid Metabolism: Potential Roles of the Lipoxygenase Pathway.},
	journal = {FASEB J},
	year = {2026},
	abstract = {Numerous studies support that gut microbiota regulate adipose inflammation and function, thereby influencing the development of obesity, diabetes, and associated metabolic disorders; however, the underlying mechanisms remain not fully elucidated. While previous studies on microbiota-adipose interactions have primarily focused on how gut microbiota modulate adipose protein-based mediators, the role of lipid mediators (LMs), lipid-based signaling molecules crucial for adipose homeostasis, remains unclear. In this study, we used high-performance liquid chromatography-tandem mass spectrometry (LC-MS/MS)-based targeted lipidomics, which can quantify over 100 LMs, to compare LM profiles in adipose tissues from germ-free (GF) and conventionally raised (specific pathogen-free, SPF) mice. We found that 5- and 12/15-lipoxygenase (LOX)-derived LMs were among the most significantly altered metabolites in conventionally raised mice compared to GF controls. Mechanistically, the effects of the gut microbiota are associated with two potential pathways: (1) downregulating transcriptional expression of 5- and 12/15-LOX in adipose tissue, and (2) lowering circulating levels of 5- and 12/15-LOX-derived metabolites. Given the potent biological activities of LOX-derived LMs, these findings may suggest a novel mechanism by which gut microbiota modulate adipose function and influence disease development.},
	doi = {10.1096/fj.202504725R},
	pmid = {41733824 [Indexed for MEDLINE]}
}

@ARTICLE{10.1039/d5fo05239d,
	author = {Jing N and Mu T and Bian X and Zhao H and Li Q and Chen Z and Tang H and Li J and Guo J and Zhao K},
	title = {Fu brick tea extracts attenuate HFD induced lipid deposition by regulating the glycerolipid metabolism of gut microbiota and adipose tissue.},
	journal = {Food Funct},
	year = {2026},
	abstract = {Fu brick tea (FT), known for regulating lipid metabolism, was studied to explore its lipid-lowering mechanism by analyzing its effects on gut microbes and adipose tissue. Mice were given chow, high-fat diet (HFD), or HFD + FT aqueous extract (FTE, 400 mg per kg BW). FTE reduced HFD-induced fat deposition, altered gut microbiota (enriched the "glycerolipid metabolism" pathway, reversed HFD-suppressed Firmicutes_bacterium_ASF500), and affected epididymal fat transcriptome (genes enriched in PPAR, glycerolipid/fatty acid metabolism). Four lipid-related genes (Lipf, Lep, Kdsr, Esrra) showed reversed expression patterns, while FTE treatment demonstrated no significant in vitro effects on adipocyte differentiation. FTE may exert lipid-lowering effects via regulating gut microbe/adipose glycerolipid metabolism, with downstream metabolites playing a key role. In summary, FTE may alleviate lipid deposition by elevating Firmicutes_bacterium_ASF500 to regulate dietary derived metabolites, which may enhance Esrra-mediated fatty acid oxidation-related gene expression, thereby improving triglyceride metabolism. Further studies are warranted to elucidate the specific roles and interactions of FTE's potential microbial and gene targets.},
	doi = {10.1039/d5fo05239d},
	pmid = {41729608 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2026.1742993,
	author = {Park MK and Cho M and Yu HS},
	title = {Macrophage migration inhibitory factor from nematode parasite as a novel approach to combat obesity and its metabolic complications.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {OBJECTIVE: Obesity is a complex chronic disease characterized by excessive fat accumulation, dysregulation of energy homeostasis, and associated mild inflammation, significantly increasing the risk of metabolic diseases, cardiovascular diseases, and other chronic diseases. Addressing this requires innovative approaches targeting the underlying mechanisms. This study investigates the therapeutic effects of Anisakis simplex-derived macrophage migration inhibitory factor (1) on adipogenesis, lipid metabolism, and inflammation in high-fat diet (2)-induced obesity. METHODS: We evaluated the effects of rAs-MIF on adipocyte differentiation, lipid droplet formation, and expression of adipogenic and inflammatory genes in 3T3-L1 cells. In addition, we investigated the effects of orally administered rAs-MIF on lipid accumulation, glucose metabolism, serum biochemical markers, and immune regulation in mice fed a 45% high-fat diet. RESULTS: rAs-MIF dose-dependently reduced lipid droplet size and triglyceride accumulation, inhibited adipogenesis and inflammatory gene expression, and upregulated adiponectin levels in 3T3-L1 cells. In HFD-fed mice, rAs-MIF decreased body weight gain, fat mass, and serum lipid levels, enhanced glucose tolerance, and activated interscapular brown adipose tissue while suppressing epididymal white adipose tissue lipid synthesis. Moreover, it modulated the immune balance by promoting the polarization of anti-inflammatory macrophages and reducing the production of pro-inflammatory cytokines. CONCLUSION: rAs-MIF demonstrates a dual regulatory effect on adipogenesis and metabolism, highlighting its potential as a therapeutic candidate for obesity.},
	doi = {10.3389/fimmu.2026.1742993},
	pmid = {41727486 [Indexed for MEDLINE]},
	note = {PMC12916604}
}

@ARTICLE{10.1016/j.jacl.2025.06.016,
	author = {McNaught J},
	title = {Pathophysiology of obesity.},
	journal = {J Clin Lipidol},
	year = {2026},
	abstract = {BACKGROUND: Obesity is an increasingly common, multifactorial condition with significant consequences for patients and the healthcare system. Obesity represents a major modifiable risk factor for cardiovascular disease, type 2 diabetes and metabolic syndrome. Understanding of the pathways and mechanisms involved in the development of obesity will allow for further advancement in treatment modalities. SOURCES OF MATERIAL: Evidence was drawn from current peer-reviewed literature addressing the pathophysiology of obesity identified via PubMed searches. ABSTRACT OF FINDINGS: Obesity results from impaired energy homeostasis and chronic positive energy balance. The etiology of the positive energy balance is often a complex interplay of genetic, environmental, neurohormonal, and psychosocial factors. This paper discusses the pathophysiology of obesity. Topics included in this discussion are the genetics of obesity, the process of energy regulation and metabolism of adipose tissue. Also discussed is how visceral obesity is especially harmful, as it promotes insulin resistance, altered lipid metabolism, and inflammation. CONCLUSION: Understanding the underlying pathophysiology of obesity is crucial for making advances in treating this condition with a more individualized approach.},
	doi = {10.1016/j.jacl.2025.06.016},
	pmid = {41708211 [Indexed for MEDLINE]}
}

@ARTICLE{10.2337/db25-0979,
	author = {Lin S and Lytle KA and Fink N and Jensen MD},
	title = {Adipose Tissue Resistance to the Antilipolytic Effect of Insulin and Niacin in Humans With Obesity.},
	journal = {Diabetes},
	year = {2026},
	abstract = {Adipose tissue (AT) lipolysis insulin resistance results in excess free fatty acid (FFA) release. We tested the hypothesis that the ability of insulin to suppress AT lipolysis is unrelated to the ability of niacin to suppress lipolysis, because niacin acts through a different proximal signaling pathway. Ten volunteers (5 women and 5 men) with upper-body obesity and/or type 2 diabetes mellitus (T2DM) underwent two study visits with overnight intravenous infusions of niacin (1.4 mg/min) or saline, followed by a hyperinsulinemic-euglycemic clamp. FFA-palmitate Ra was measured using [U-13C] and [2H9]palmitate infusions; abdominal AT biopsies were performed before and during the insulin clamp. The suppression of FFA-palmitate Ra by insulin on the saline control day and by niacin after an overnight infusion were highly correlated (r = -0.93, P < 0.001). Fasting AT Akt (pAktS473/474-to-panAkt ratio, P = 0.01) and perilipin 1 (PLN1) (pPLN1S552-to-panPLN1 ratio, P = 0.02) phosphorylation were less during niacin treatment than in the saline control study. Because the suppression of lipolysis by insulin and niacin are highly correlated within individuals and because niacin and insulin act through different proximal signaling pathways, we propose dysregulated AT lipolysis in obesity/T2DM is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance." ARTICLE HIGHLIGHTS: We undertook this study to compare adipose tissue lipolysis responses to insulin and niacin in humans. We tested the hypothesis that adipose tissue insulin resistance would be unrelated to adipose tissue niacin resistance. The suppression of lipolysis by insulin and niacin were highly correlated. Dysregulated adipose tissue lipolysis in obesity/type 2 diabetes is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance."},
	doi = {10.2337/db25-0979},
	pmid = {41701570 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fendo.2025.1736033,
	author = {Spadafora R and Zhang J and Nirmala NR and Li X and O'Tierney-Ginn P},
	title = {Placental mRNA and miRNA dynamics associated with lipid metabolism pathways in pregnancies affected by obesity.},
	journal = {Front Endocrinol (Lausanne)},
	year = {2026},
	abstract = {INTRODUCTION: Maternal obesity (pregravid body mass index >30 kg/m2), which has reached epidemic levels in the US, increases the incidence of cardiovascular disease and all cause premature death in the offspring. The placenta modulates fetal access to lipids and other nutrients and is considered a key player in fetal growth and maturation. However, the complex interplay between dysregulated metabolism in mothers with obesity and placental pathways mediating impacts on fetal development that predispose offspring to morbidities later in life, is poorly understood. METHODS: We used unbiased Whole Genome Correlation Network Analysis (WGCNA) in 39 full-term unlabored placentas from mothers affected by obesity to explore relationships between coding and non-coding placental transcripts with maternal and fetal metabolic variables. RESULTS: We identified positive correlations between members of the Rho network, a key inflammation regulator, with maternal leptin and cord blood free fatty acids (cbFFA). Furthermore, we identified negative correlations between epigenetic regulators and the lipid metabolism drivers SMUG1 and CDS1, with cbFFA. A set of placental miRNAs showed positive correlations with cbFFA. Using mirTarRnaSeq, an R/Bioconductor package, we predicted interactions between placental coding genes and miRNA, which correlated negatively and positively with cbFFA, respectively. Several FFA-associated miRNAs (miR-23b cluster, -168, -138, -6825, -6845) have been previously associated with obesity in animal models and human cohorts. DISCUSSION: Further studies are required to investigate the role that the Rho network plays in placental inflammation and the link between miRNAs and the predisposition towards cardiovascular diseases in the offspring of obese mothers.},
	doi = {10.3389/fendo.2025.1736033},
	pmid = {41684451 [Indexed for MEDLINE]},
	note = {PMC12890621}
}

@ARTICLE{10.3390/ijms27031440,
	author = {Wu H and Xu X and Chen J and Morisseau C and Hammock BD and Tseng YH and Zhao L},
	title = {Transplantation of Soluble Epoxide Hydrolase Inhibitor-Treated Human Brown Adipocytes Promotes Adipose Tissue Activation in High-Fat-Diet-Fed Nude Mice.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Brown adipose tissue (BAT) plays a key role in non-shivering thermogenesis and is a promising target for enhancing energy expenditure to combat obesity. Soluble epoxide hydrolase (sEH) is a cytosolic enzyme that catalyzes the conversion of epoxy fatty acids into less active diols. We have reported that local administration of the sEH inhibitor, t-TUCB, to the endogenous interscapular BAT (iBAT) of diet-induced obese mice decreased serum triglycerides and enhanced the expression of essential genes associated with lipid metabolism. Here, the effects of sEH inhibition by t-AUCB were assessed on human brown adipocyte (HuBr) differentiation and in nude mice transplanted with t-AUCB-treated HuBr. HuBr cells were differentiated with t-AUCB (1-10 μM) or the vehicle (0.1% DMSO). HuBr differentiated with t-AUCB at 5 μM (AUCB 5) or DMSO was mixed with matrix gel and transplanted into the nude mice. The mice were then fed a high-fat diet for eight weeks. The mice receiving AUCB 5-treated HuBr exhibited markedly reduced lipid accumulation in the iBAT compared with DMSO or matrix-only controls, along with increased protein expression of thermogenic PGC1α and UCP1, fatty acid transporter CD36, and CPT1A in the iBAT, while the NFκB inflammatory pathways were suppressed in both the AUCB 5 and DMSO groups. Moreover, the PGC1α and CPT1A protein levels were elevated, and the adipocyte sizes were decreased in the epididymal white adipose tissue of the AUCB 5 group. Our findings indicate that the transplantation of HuBr treated with AUCB 5 may stimulate thermogenesis, enhance lipid metabolism, and reduce inflammation in iBAT.},
	doi = {10.3390/ijms27031440},
	pmid = {41683861 [Indexed for MEDLINE]},
	note = {PMC12898555}
}

@ARTICLE{10.3390/ijms27031306,
	author = {Sobczyński J, Nowaczyński F, Smolińska K and Lachowicz-Radulska J and Serefko A and Szopa A},
	title = {Natural Bioactive Compounds Targeting FABP4 in Adipogenesis and Obesity: Evidence from In Vitro and In Vivo Studies.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {FABP4 (fatty acid-binding protein 4) is a lipid chaperone and secreted adipokine linking dysregulated fatty acid handling with inflammation, cellular stress, and insulin resistance in obesity. By modulating nuclear receptor signaling (notably PPARγ) and enhancing NF-κB/MAPK activation in adipocytes and macrophages, FABP4 contributes to maladaptive adipose remodeling and systemic metabolic decline. This review critically summarizes recent preclinical evidence on natural bioactive compounds that regulate FABP4 expression and associated adipogenic programs in models of adipogenesis and diet-induced obesity. Data from 3T3-L1/OP9 adipocytes, rodent studies, and selected alternative models indicate that many plant-derived extracts and phytochemicals (e.g., polyphenols, saponins, coumarins, terpenoids, and fermented products) down-regulate FABP4 at mRNA and/or protein levels. These effects are frequently accompanied by suppression of PPARγ/C/EBPα/SREBP1c signaling, activation of AMPK-related pathways, reduced lipid accumulation, and improved metabolic outcomes including lower weight gain, reduced adipocyte hypertrophy, improved steatosis, and favorable serum lipid profiles. Natural compounds from non-plant sources (animal- and microbe-derived metabolites) further broaden FABP4-targeting strategies, supporting FABP4 as a cross-class therapeutic node. Key translational barriers include poor extract standardization, incomplete identification of active constituents, limited oral bioavailability, microbiome-dependent variability, and scarce clinical validation. Future work should prioritize well-characterized lead scaffolds, targeted delivery, rational combinations, and standardized, adequately powered clinical trials assessing dose, durability of FABP4 suppression, and cardiometabolic safety.},
	doi = {10.3390/ijms27031306},
	pmid = {41683732 [Indexed for MEDLINE]},
	note = {PMC12898738}
}

@ARTICLE{10.3390/ijms27031186,
	author = {Ábel T and Csobod Csajbókné É},
	title = {Semaglutide-Mediated Remodeling of Adipose Tissue in Type 2 Diabetes: Molecular Mechanisms Beyond Glycemic Control.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Type 2 diabetes mellitus (T2DM) is characterized not only by chronic hyperglycemia but also by profound adipose tissue dysfunction, including impaired lipid handling, low-grade inflammation, mitochondrial dysfunction, and extracellular matrix (ECM) remodeling. These adipose tissue alterations play a central role in the development of systemic insulin resistance, ectopic lipid accumulation, and cardiometabolic complications. Glucagon-like peptide-1 receptor agonists (GLP-1RAs), particularly semaglutide, have emerged as highly effective therapies for T2DM and obesity. While their glucose-lowering and appetite-suppressive effects are well established, accumulating evidence indicates that semaglutide exerts pleiotropic metabolic actions that extend beyond glycemic control, with adipose tissue representing a key target organ. This review synthesizes current preclinical and clinical evidence on the molecular and cellular mechanisms through which semaglutide modulates adipose tissue biology in T2DM. We discuss depot-specific effects on visceral and subcutaneous adipose tissue, regulation of adipocyte lipid metabolism and lipolysis, enhancement of mitochondrial biogenesis and oxidative capacity, induction of beige adipocyte programming, modulation of adipokine and cytokine secretion, immunometabolic remodeling, and attenuation of adipose tissue fibrosis and ECM stiffness. Collectively, available data indicate that semaglutide promotes a functional shift in adipose tissue from a pro-inflammatory, lipid-storing phenotype toward a more oxidative, insulin-sensitive, and metabolically flexible state. These adipose-centered adaptations likely contribute to improvements in systemic insulin sensitivity, reduction in ectopic fat deposition, and attenuation of cardiometabolic risk observed in patients with T2DM. Despite compelling mechanistic insights, much of the current evidence derives from animal models or in vitro systems. Human adipose tissue-focused studies integrating molecular profiling, advanced imaging, and longitudinal clinical data are therefore needed to fully elucidate the extra-glycemic actions of semaglutide and to translate these findings into adipose-targeted therapeutic strategies.},
	doi = {10.3390/ijms27031186},
	pmid = {41683613 [Indexed for MEDLINE]},
	note = {PMC12898281}
}
